/**
 * Counts \questionitem occurrences in every QBT question .tex file and writes
 * src/data/questionCounts.generated.ts, keyed by the /tex/... PDF path used
 * in resources.ts. Run automatically via npm lifecycle hooks before build/dev/check.
 *
 * The compute/render functions are exported pure (no I/O) so that
 * `check-generated.mjs` can verify the on-disk generated file matches what
 * this script *would* produce right now without re-writing it.
 */

import { readFileSync, writeFileSync, readdirSync } from 'node:fs';
import { join, resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, '..');
const publicDir = join(repoRoot, 'public');

/**
 * Recursively finds all _QBT__*.tex files (excluding solutions) under `dir`.
 * Exported so tests can drive it against a temp fixture tree.
 *
 * @param {string} dir
 * @returns {string[]}
 */
export function findQbtTexFiles(dir) {
  const results = [];
  let entries;
  try {
    entries = readdirSync(dir, { withFileTypes: true });
  } catch {
    return results;
  }
  for (const entry of entries) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      results.push(...findQbtTexFiles(full));
    } else if (
      entry.name.startsWith('_QBT__') &&
      !entry.name.startsWith('_QBT___Solns') &&
      entry.name.endsWith('.tex')
    ) {
      results.push(full);
    }
  }
  return results;
}

/**
 * Counts `\questionitem` use-sites in a tex file body, excluding any
 * `\newcommand`/`\renewcommand` definition lines.
 *
 * @param {string} content
 * @returns {number}
 */
export function countQuestionitemsInText(content) {
  return content
    .split('\n')
    .filter((line) => /\\questionitem/.test(line) && !/\\(?:new|renew)command/.test(line))
    .length;
}

/**
 * Computes the sorted `[/tex/...pdf, count][]` entries that the generated
 * file would contain. Pure — reads the filesystem but produces no output.
 *
 * @param {string} [publicDirArg] - defaults to the repo's `public/` dir.
 * @returns {[string, number][]}
 */
export function computeQuestionCounts(publicDirArg = publicDir) {
  const texFiles = findQbtTexFiles(join(publicDirArg, 'tex'));
  const counts = {};
  for (const texPath of texFiles) {
    const content = readFileSync(texPath, 'utf-8');
    const rel = texPath.slice(publicDirArg.length).replace(/\\/g, '/');
    const filePath = rel.replace(/\.tex$/, '.pdf');
    counts[filePath] = countQuestionitemsInText(content);
  }
  return Object.entries(counts).sort(([a], [b]) => a.localeCompare(b));
}

/**
 * Renders the `questionCounts.generated.ts` file body for a given set of
 * entries. Pure — output is byte-stable for a given input.
 *
 * @param {[string, number][]} entries
 * @returns {string}
 */
export function renderQuestionCountsModule(entries) {
  const lines = [
    '// AUTO-GENERATED by scripts/count-questions.mjs — do not edit manually.',
    '// Regenerated on every `npm run build`, `npm run dev`, and `npm run check`.',
    'export const questionCounts: Record<string, number> = {',
    ...entries.map(([path, count]) => `  '${path}': ${count},`),
    '};',
    '',
  ];
  return lines.join('\n');
}

/**
 * Path the generator writes to. Exported so `check-generated.mjs` can read
 * the same target without duplicating the convention.
 */
export const GENERATED_PATH = join(repoRoot, 'src', 'data', 'questionCounts.generated.ts');

function main() {
  const entries = computeQuestionCounts();
  writeFileSync(GENERATED_PATH, renderQuestionCountsModule(entries), 'utf-8');
  console.log(
    `[count-questions] ${entries.length} entries written to src/data/questionCounts.generated.ts`,
  );
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  main();
}
